SELECT timeline_entry_id AS "id",category,event_type AS "eventType", schema_version AS "schemaVersion",occurred_at AS "occurredAt",received_at AS "receivedAt", actor_id AS "actorId",resource_type AS "resourceType",resource_id AS "resourceId", resource_version AS "resourceVersion",resource_code AS "resourceCode", outcome_code AS "outcomeCode",correlation_id AS "correlationId", display_template_code AS "displayTemplateCode", display_template_version AS "displayTemplateVersion" FROM rdm_work_order_timeline_entry WHERE tenant_id=#{tenantId} AND work_order_id=#{workOrderId} AND rebuild_generation=#{rebuildGeneration}
AND (occurred_at,timeline_entry_id) < (#{beforeOccurredAt},#{beforeEntryId})
ORDER BY occurred_at DESC,timeline_entry_id DESC LIMIT #{fetchSize}

SELECT max(received_at) FROM rdm_work_order_timeline_entry
 WHERE tenant_id=#{tenantId} AND work_order_id=#{workOrderId}
   AND rebuild_generation=#{rebuildGeneration}
